{
  "situations": [
    {
      "dialogue": "Our checkout link starts with `http://checkout.plantshop.com/cart`, and browsers flag it as Not Secure right before customers enter their card numbers.",
      "imagePrompt": "A browser window showing an online shopping cart page. The address bar displays the URL http://checkout.plantshop.com/cart with a warning label reading Not Secure next to it. The http:// portion at the start of the URL is visually prominent.",
      "options": [
        {
          "feedback": "Right. Changing the scheme from `http` to `https` tells the browser to use an encrypted connection, which removes the Not Secure warning and protects card data.",
          "isCorrect": true,
          "text": "The scheme"
        },
        {
          "feedback": "The domain `checkout.plantshop.com` is the correct server. Changing it would send customers somewhere else entirely, and the connection would still be unencrypted.",
          "isCorrect": false,
          "text": "The domain"
        },
        {
          "feedback": "The path `/cart` just picks which page loads on the server. It has no effect on whether the connection is encrypted.",
          "isCorrect": false,
          "text": "The path"
        },
        {
          "feedback": "There is no query string here, and adding one would only pass extra parameters to the page. It cannot make the connection encrypted.",
          "isCorrect": false,
          "text": "The query string"
        }
      ],
      "question": "Which URL part should we change to get an encrypted connection?"
    },
    {
      "dialogue": "{{NAME}}, an email button says MyBank Login, but hovering over it shows `https://mybank.secure-login-example.ru/account`. The customer wants to know if clicking it really contacts their bank's server.",
      "imagePrompt": "A close-up of an email on a screen with a blue button labeled MyBank Login. A tooltip near the cursor shows the URL https://mybank.secure-login-example.ru/account. The domain portion of the URL stands out.",
      "options": [
        {
          "feedback": "Exactly. The domain names the server the browser will contact. Here it is `secure-login-example.ru`, not the bank's real domain, so this is not the bank's site no matter what the button says.",
          "isCorrect": true,
          "text": "The domain"
        },
        {
          "feedback": "The scheme `https` only means the connection is encrypted. A phishing site can use `https` too, so it says nothing about who owns the server.",
          "isCorrect": false,
          "text": "The scheme"
        },
        {
          "feedback": "The path `/account` is chosen by whoever runs the server. Any site can create a path that looks bank-like, so it cannot prove where the request goes.",
          "isCorrect": false,
          "text": "The path"
        },
        {
          "feedback": "There is no fragment here, and a fragment only controls scrolling within a page. It never determines which server receives the request.",
          "isCorrect": false,
          "text": "The fragment"
        }
      ],
      "question": "Which part of the URL tells you which server the browser will actually contact?"
    },
    {
      "dialogue": "Visitors keep hitting a 404 error on `https://citylibrary.org/events/summer-reading`, but the homepage at the same address loads perfectly.",
      "imagePrompt": "A browser showing a 404 Page Not Found error. The address bar reads https://citylibrary.org/events/summer-reading. The path portion /events/summer-reading is highlighted after the domain.",
      "options": [
        {
          "feedback": "Correct. Since the homepage loads, the server and connection are fine. A 404 means the server could not find the resource at that path, so `/events/summer-reading` likely changed or was removed.",
          "isCorrect": true,
          "text": "The path"
        },
        {
          "feedback": "If the domain were wrong, the homepage would not load either. The browser is clearly reaching the right server, which is what returned the 404.",
          "isCorrect": false,
          "text": "The domain"
        },
        {
          "feedback": "The scheme `https` controls encryption, not which page exists. A wrong scheme would cause a connection problem, not a 404 from a server that otherwise responds fine.",
          "isCorrect": false,
          "text": "The scheme"
        },
        {
          "feedback": "There is no query string in this URL, and query parameters filter or configure a page. A missing page location is a path problem, not a filter problem.",
          "isCorrect": false,
          "text": "The query string"
        }
      ],
      "question": "Which URL part most likely points to a page that no longer exists?"
    },
    {
      "dialogue": "Our ad promises size 8 sneakers, but the link `https://shoes.example.com/catalog?size=10&color=red` opens the catalog filtered to the wrong size. Support tickets are piling up.",
      "imagePrompt": "An online shoe store catalog page showing red sneakers labeled size 10. The browser address bar shows https://shoes.example.com/catalog?size=10&color=red, with the query string ?size=10&color=red visible after the path.",
      "options": [
        {
          "feedback": "Right. The part after `?` holds the filter parameters. Changing `size=10` to `size=8` in the query string will make the catalog load with the size the ad promised.",
          "isCorrect": true,
          "text": "Edit the query string"
        },
        {
          "feedback": "The path `/catalog` correctly points to the catalog page. Editing it would send shoppers to a different page instead of fixing the filter values.",
          "isCorrect": false,
          "text": "Edit the path"
        },
        {
          "feedback": "A fragment after `#` only scrolls to a position on the page. It is not sent as a filter, so it cannot change which sizes the catalog shows.",
          "isCorrect": false,
          "text": "Edit the fragment"
        },
        {
          "feedback": "The domain `shoes.example.com` is the right store. Changing it would point the ad at a different server entirely, and the size filter would still be wrong.",
          "isCorrect": false,
          "text": "Edit the domain"
        }
      ],
      "question": "Which part of the URL should we edit so the link shows size 8?"
    },
    {
      "dialogue": "The help link is supposed to drop readers right at the refund policy halfway down our FAQ page, but it always opens at the very top. The URL ends at `/faq` with nothing after it.",
      "imagePrompt": "A long FAQ webpage viewed at the top, with a section heading Refund Policy visible far down the page in a minimized page overview. The browser address bar shows https://help.example.com/faq with nothing after the path.",
      "options": [
        {
          "feedback": "Correct. A fragment like `#refund-policy` tells the browser to scroll straight to that section's anchor on the page, without changing which page loads.",
          "isCorrect": true,
          "text": "A fragment after `#`"
        },
        {
          "feedback": "A query string after `?` sends parameters to the server, like filters or search terms. It does not tell the browser where to scroll on the page.",
          "isCorrect": false,
          "text": "A query string after `?`"
        },
        {
          "feedback": "Extending the path would ask the server for a different page, likely causing a 404. The refund policy is a section on this page, not a separate page.",
          "isCorrect": false,
          "text": "A longer path"
        },
        {
          "feedback": "A new subdomain changes which server or site area the browser contacts. That is a much bigger change than jumping to a spot on the page you already have.",
          "isCorrect": false,
          "text": "A new subdomain"
        }
      ],
      "question": "What should we add to the URL so the browser jumps to that section?"
    },
    {
      "dialogue": "{{NAME}}, we're testing the docs site on a very slow connection, and every reload takes ages. We want readers to hop between sections of one long page without waiting for the network at all.",
      "imagePrompt": "A laptop showing a long technical documentation page with a table of contents sidebar. The address bar reads https://docs.example.com/guide#setup. A slow connection indicator icon is visible near the browser toolbar.",
      "options": [
        {
          "feedback": "Exactly. Changing only the fragment after `#` makes the browser scroll to a different anchor on the page it already has. No new request goes to the server, so it works instantly even offline.",
          "isCorrect": true,
          "text": "Changing the fragment"
        },
        {
          "feedback": "Changing the query string sends different parameters to the server, so the browser makes a new network request and reloads the page.",
          "isCorrect": false,
          "text": "Changing the query string"
        },
        {
          "feedback": "Changing the path asks the server for a different page entirely, which always means a new network request and a wait on a slow connection.",
          "isCorrect": false,
          "text": "Changing the path"
        },
        {
          "feedback": "Changing the domain contacts a completely different server. That is the most expensive change here, not a way to avoid the network.",
          "isCorrect": false,
          "text": "Changing the domain"
        }
      ],
      "question": "Which URL change happens without a new network request?"
    }
  ]
}

{
  "situations": [
    {
      "dialogue": "{{NAME}}, before we assign probabilities for this board game spinner, look at my outcome list. The spinner has four equal sections, but I wrote down red, blue, green and stopped there.",
      "imagePrompt": "A colorful board game spinner divided into four equal sections colored red, blue, green, and yellow, next to a handwritten paper list showing only three words: red, blue, green.",
      "options": [
        {
          "feedback": "Right. A sample space must list every possible outcome, and the spinner can clearly land on yellow. Without it, any probabilities we compute will be wrong.",
          "isCorrect": true,
          "text": "Add yellow to the list"
        },
        {
          "feedback": "Green is a real section on the spinner, so it belongs in the sample space. Removing it would make the list even less complete. The list needs yellow added instead.",
          "isCorrect": false,
          "text": "Remove green from the list"
        },
        {
          "feedback": "Red and blue are separate sections, so they are separate outcomes. Merging them would hide a real distinction. The actual problem is that yellow is missing.",
          "isCorrect": false,
          "text": "Merge red and blue"
        },
        {
          "feedback": "The order of outcomes never affects a sample space. The real flaw is that one possible outcome, yellow, is missing entirely.",
          "isCorrect": false,
          "text": "Reorder the outcomes"
        }
      ],
      "question": "What correction does this sample space need before we define events?"
    },
    {
      "dialogue": "A study buddy typed up the outcomes for rolling one standard six-sided die and got a list of seven entries: 1, 2, 3, 4, 5, 5, 6. Now every probability calculation using the list comes out slightly off.",
      "imagePrompt": "A single white six-sided die on a desk beside a notebook page listing outcomes vertically: 1, 2, 3, 4, 5, 5, 6, with the two 5 entries clearly visible.",
      "options": [
        {
          "feedback": "Exactly. Each outcome must appear exactly once. The duplicated 5 inflates the list to seven entries and would make 5 seem more likely than it really is.",
          "isCorrect": true,
          "text": "Delete one of the 5s"
        },
        {
          "feedback": "Adding a second 6 would just create another duplicate. The die has six distinct faces, so the fix is removing the extra 5, not padding the list.",
          "isCorrect": false,
          "text": "Add another 6"
        },
        {
          "feedback": "5 and 6 are different faces, so they must stay as separate outcomes. Combining them would merge two distinct results. The problem is the repeated 5.",
          "isCorrect": false,
          "text": "Combine 5 and 6 into one entry"
        },
        {
          "feedback": "6 is a real face of the die, so it belongs in the sample space. Removing it would leave the list incomplete. The extra entry is the second 5, not the 6.",
          "isCorrect": false,
          "text": "Remove the 6"
        }
      ],
      "question": "Which correction fixes the sample space?"
    },
    {
      "dialogue": "Our customer survey asks people to pick one age group: under 20, 18 to 35, or over 35. Several respondents aged 18 and 19 got counted in two groups, so the totals add up to more than the number of people surveyed.",
      "imagePrompt": "A survey form on a clipboard with three checkbox options labeled: Under 20, 18–35, Over 35, and a tally sheet next to it where the column totals exceed the circled number of respondents.",
      "options": [
        {
          "feedback": "Correct. With \"under 18\" and \"18–35\", no age fits two groups, so the outcomes become mutually exclusive and each person counts exactly once.",
          "isCorrect": true,
          "text": "Change \"under 20\" to \"under 18\""
        },
        {
          "feedback": "Ages 18 and 19 are already covered by two existing groups. Adding a third group for them would make the overlap worse, not fix it. The boundary itself needs to change.",
          "isCorrect": false,
          "text": "Add a group for ages 18–19"
        },
        {
          "feedback": "Removing that group would leave everyone aged 20 to 35 with no category at all, trading an overlap problem for a missing-outcome problem. Adjusting the boundary is the real fix.",
          "isCorrect": false,
          "text": "Remove the \"18–35\" group"
        },
        {
          "feedback": "Merging everything into one group destroys the information the survey is trying to collect. The overlap only exists at ages 18 and 19, so fixing that boundary is enough.",
          "isCorrect": false,
          "text": "Merge all three groups"
        }
      ],
      "question": "Which repair makes the age groups mutually exclusive?"
    },
    {
      "dialogue": "We are writing the rules for a dice game, and a bonus only triggers when two events can never happen on the same roll of one six-sided die. I need you to pick the pair that qualifies.",
      "imagePrompt": "A single red six-sided die mid-roll on a game board, with a rules card beside it showing a blank line labeled: bonus pair.",
      "options": [
        {
          "feedback": "Right. 3 is odd, so no single roll can be both even and a 3. These events share no outcomes, which is exactly what mutually exclusive means.",
          "isCorrect": true,
          "text": "Even, and roll a 3"
        },
        {
          "feedback": "A roll of 6 is both even and greater than 4, so these events overlap on that outcome. They can happen together, so they are not mutually exclusive.",
          "isCorrect": false,
          "text": "Even, and greater than 4"
        },
        {
          "feedback": "Rolls of 1 and 3 are both odd and less than 4, so these events share outcomes. A pair that overlaps cannot trigger the bonus rule.",
          "isCorrect": false,
          "text": "Odd, and less than 4"
        },
        {
          "feedback": "Rolls of 3 and 4 are both greater than 2 and less than 5, so these events overlap. Only a pair with no shared outcomes is mutually exclusive.",
          "isCorrect": false,
          "text": "Greater than 2, and less than 5"
        }
      ],
      "question": "Which pair of events is mutually exclusive on one roll?"
    },
    {
      "dialogue": "{{NAME}}, my cousin says flipping a coin twice has only three outcomes: two heads, two tails, or one of each. Her bet payouts are based on that count, and something about it feels off to me.",
      "imagePrompt": "Two coins on a table, one showing heads and one showing tails, next to a handwritten note listing three lines: two heads, two tails, one of each, with a question mark drawn beside the list.",
      "options": [
        {
          "feedback": "Correct. The full sample space is HH, HT, TH, TT. \"One of each\" hides two distinct outcomes, heads-then-tails and tails-then-heads, so her payouts undercount that result.",
          "isCorrect": true,
          "text": "4 outcomes"
        },
        {
          "feedback": "That is the cousin's count, and it overlaps two different results under one label. Heads-then-tails and tails-then-heads are separate outcomes, so the true sample space is larger.",
          "isCorrect": false,
          "text": "3 outcomes"
        },
        {
          "feedback": "Two is the number of outcomes for a single flip. With two flips, each result of the first flip pairs with each result of the second, giving more than two combinations.",
          "isCorrect": false,
          "text": "2 outcomes"
        },
        {
          "feedback": "Eight is the count for three flips. Two flips give two possibilities on each flip, and \\(2 \\times 2 = 4\\) distinct ordered outcomes.",
          "isCorrect": false,
          "text": "8 outcomes"
        }
      ],
      "question": "How many outcomes are in the full sample space for two coin flips?"
    },
    {
      "dialogue": "The vet clinic's intake form records each patient as dog, cat, or fish, and one selection is required. This morning someone brought in a hamster, and the receptionist could not submit the form at all.",
      "imagePrompt": "A computer screen showing a veterinary intake form with a required dropdown menu open, listing only three choices: Dog, Cat, Fish, and a red error message reading: selection required. A hamster sits in a small carrier beside the keyboard.",
      "options": [
        {
          "feedback": "Exactly. A valid sample space covers every possible outcome of the trial. A real patient arrived that fits no listed option, which proves the outcome list is incomplete.",
          "isCorrect": true,
          "text": "It is missing an outcome"
        },
        {
          "feedback": "No option appears twice on the form, so there is no duplicate. The failure came from a real case that had no option at all, which points to a missing outcome.",
          "isCorrect": false,
          "text": "It has a duplicated outcome"
        },
        {
          "feedback": "Dog, cat, and fish do not overlap; no animal fits two of those labels at once. The hamster fit zero labels, which is a completeness problem, not an overlap problem.",
          "isCorrect": false,
          "text": "Its labels overlap"
        },
        {
          "feedback": "Three options is not too many; each one describes real patients the clinic sees. The problem is the opposite: at least one possible outcome was never listed.",
          "isCorrect": false,
          "text": "It has too many outcomes"
        }
      ],
      "question": "What does this failure reveal about the form's sample space?"
    }
  ]
}

{
  "situations": [
    {
      "dialogue": "{{NAME}}, I tied one end of this long gym rope to the wall and snapped the other end. A hump raced all the way to the wall, but I never let go of my end. Something had to carry that pulse across the room.",
      "imagePrompt": "A long rope stretched across a gym, tied to a wall anchor, with a single visible wave hump traveling along its length while a hand holds the near end steady.",
      "options": [
        {
          "feedback": "Right. The rope is the medium: each section of rope pulls on the next, passing the disturbance along while the rope itself stays put end to end.",
          "isCorrect": true,
          "text": "The rope itself"
        },
        {
          "feedback": "The air isn't what moves the hump here. The pulse travels along the rope because neighboring sections of rope tug on each other, not because air pushes it.",
          "isCorrect": false,
          "text": "The surrounding air"
        },
        {
          "feedback": "Your hand created the disturbance, but it stayed at one end. A medium is the matter the wave travels through, and that matter is the rope.",
          "isCorrect": false,
          "text": "The hand that snapped it"
        },
        {
          "feedback": "The wall anchor just holds the far end in place. The pulse reached the wall by moving through the rope, section by section.",
          "isCorrect": false,
          "text": "The wall anchor"
        }
      ],
      "question": "What is the medium carrying this wave pulse?"
    },
    {
      "dialogue": "There's a toy duck floating on the pond, and ripples from a dropped stone keep passing under it. The ripples clearly travel toward the shore, but after a full minute the duck is still bobbing in almost the same spot.",
      "imagePrompt": "A small toy duck bobbing on a pond with circular ripples spreading outward past it toward the shore, the duck staying centered in nearly the same position.",
      "options": [
        {
          "feedback": "Exactly. The water is the medium: each bit of water oscillates up and down in place, passing the disturbance along. Energy travels outward, but the water and the duck mostly stay put.",
          "isCorrect": true,
          "text": "Water oscillates in place"
        },
        {
          "feedback": "If the water itself flowed to shore with each ripple, the duck would ride along with it. It doesn't, because the water only moves locally while the wave shape travels.",
          "isCorrect": false,
          "text": "Water flows toward shore"
        },
        {
          "feedback": "Weight isn't the reason. Even a very light leaf would bob in place, because the medium itself doesn't travel with the wave.",
          "isCorrect": false,
          "text": "The duck is too heavy"
        },
        {
          "feedback": "The ripples clearly carry energy — they lift the duck up and down. What they don't do is transport the water itself across the pond.",
          "isCorrect": false,
          "text": "The ripples carry no energy"
        },
        {
          "feedback": "",
          "isCorrect": false,
          "text": ""
        }
      ],
      "question": "Why does the duck stay in place while the ripples travel?"
    },
    {
      "dialogue": "In the physics lab we sealed an electric bell inside a glass jar and started the vacuum pump. The clapper is still visibly striking the bell, but as the pump removes more and more air, the ringing gets fainter and fainter.",
      "imagePrompt": "An electric bell suspended inside a sealed glass jar connected to a vacuum pump, the clapper visibly striking the bell, with a pressure gauge showing near-zero air pressure.",
      "options": [
        {
          "feedback": "Correct. Sound is a mechanical wave, so it needs matter to travel through. The air molecules inside the jar were the medium, and removing them leaves nothing to pass the vibration along.",
          "isCorrect": true,
          "text": "The air medium is being removed"
        },
        {
          "feedback": "Glass doesn't block all sound — you could hear the bell clearly before the pump started. What changed is the air inside the jar, not the glass.",
          "isCorrect": false,
          "text": "Glass blocks all sound"
        },
        {
          "feedback": "You can see the clapper still striking the bell. The vibration source is fine; what's disappearing is the matter that would carry that vibration to your ear.",
          "isCorrect": false,
          "text": "The bell stopped vibrating"
        },
        {
          "feedback": "The pump removes air, not electricity, and the clapper is still moving. The fading sound comes from losing the medium, not losing power.",
          "isCorrect": false,
          "text": "The pump drains the bell's power"
        }
      ],
      "question": "Why is the ringing fading?"
    },
    {
      "dialogue": "{{NAME}}, our seismometer just recorded strong shaking from an earthquake whose epicenter is 200 miles away. Nothing visible crossed the distance between us and the epicenter, yet the tremor arrived here within minutes.",
      "imagePrompt": "A seismometer on a table drawing a jagged tremor trace on paper, next to a map marking an earthquake epicenter 200 miles away from the station.",
      "options": [
        {
          "feedback": "Right. The solid ground is the medium. Rock particles pass the disturbance to neighboring rock, so the seismic wave travels hundreds of miles while each bit of ground only shakes locally.",
          "isCorrect": true,
          "text": "Rock and soil"
        },
        {
          "feedback": "Seismic waves like these travel through the solid earth, not the atmosphere. The seismometer sits on the ground and picked up the shaking through it.",
          "isCorrect": false,
          "text": "The air above the surface"
        },
        {
          "feedback": "The tremor didn't need any built infrastructure. It moved through the earth itself, with rock passing the vibration along to neighboring rock.",
          "isCorrect": false,
          "text": "Power and telephone lines"
        },
        {
          "feedback": "The shaking matches the distant quake's timing, so it wasn't local. A disturbance really did travel 200 miles — through the solid ground.",
          "isCorrect": false,
          "text": "Nothing; the shaking was local"
        }
      ],
      "question": "What medium carried the tremor to the seismometer?"
    },
    {
      "dialogue": "I stretched a long spring toy across the floor and stuck a bit of red tape on one coil near the middle. Now I'm about to push and pull one end sharply to send a compression pulse all the way down to the far end.",
      "imagePrompt": "A long metal spring toy stretched across a wooden floor with a small piece of red tape on one coil near the middle, a compression pulse visible traveling along the coils.",
      "options": [
        {
          "feedback": "Correct. The coils are the medium: the taped coil jiggles back and forth as the pulse passes, then settles near where it started. The disturbance travels; the medium only oscillates locally.",
          "isCorrect": true,
          "text": "Back near its original spot"
        },
        {
          "feedback": "If coils traveled with the pulse, the spring would pile up at the far end. Instead, each coil passes the push to its neighbor and stays roughly in place.",
          "isCorrect": false,
          "text": "Carried to the far end"
        },
        {
          "feedback": "The pulse moves away from your hand, but it doesn't drag coils backward toward you either. The taped coil oscillates around its position, not toward either end.",
          "isCorrect": false,
          "text": "Pulled back to your hand"
        },
        {
          "feedback": "A small piece of tape doesn't stop the wave. The pulse passes right through that coil, making it oscillate briefly before it settles in place.",
          "isCorrect": false,
          "text": "Stuck where the pulse stops"
        }
      ],
      "question": "After the pulse passes, where will the taped coil be?"
    },
    {
      "dialogue": "My cousin swears the wave machine at the pool pushes the water itself all the way from the deep end to the shallow end with every wave. I think only the disturbance travels and the water mostly stays where it is. We want to settle this today.",
      "imagePrompt": "An indoor wave pool with regular waves rolling from the deep end toward the shallow end, and a single brightly colored beach ball floating on the surface in the middle of the pool.",
      "options": [
        {
          "feedback": "Right. If the water traveled with each wave, the ball would ride steadily to the shallow end. If it mostly bobs in place while waves pass under it, that shows the medium only oscillates locally.",
          "isCorrect": true,
          "text": "Watch a floating ball"
        },
        {
          "feedback": "Wave speed tells you how fast the disturbance travels, but it says nothing about whether the water itself is transported along with it.",
          "isCorrect": false,
          "text": "Time the wave speed"
        },
        {
          "feedback": "Counting crests measures frequency, not motion of the medium. It can't settle whether the water travels or stays put.",
          "isCorrect": false,
          "text": "Count the wave crests"
        },
        {
          "feedback": "Temperature at each end doesn't reveal whether water is being carried across the pool. You need to track a marker floating on the water itself.",
          "isCorrect": false,
          "text": "Compare water temperatures"
        }
      ],
      "question": "Which check best settles the argument?"
    }
  ]
}

{
  "situations": [
    {
      "dialogue": "{{NAME}}, a lei orçamentária deste ano reservou R$ 400 mil para comprar uma ambulância, mas o extrato bancário da prefeitura mostra saldo quase zerado. O secretário quer assinar o contrato hoje mesmo.",
      "imagePrompt": "Mesa de prefeitura com dois documentos lado a lado: uma página da lei orçamentária mostrando a dotação de R$ 400.000 para ambulância e um extrato bancário impresso com saldo de R$ 3.120,00.",
      "options": [
        {
          "feedback": "Exato. A dotação é uma autorização orçamentária para realizar o gasto, mas não significa que há dinheiro em caixa. Autorização e fluxo financeiro são coisas diferentes.",
          "isCorrect": true,
          "text": "Permissão legal para gastar"
        },
        {
          "feedback": "Não. O extrato mostra o oposto: quase não há saldo. A dotação existe no orçamento, mas o dinheiro em caixa depende da arrecadação real das receitas.",
          "isCorrect": false,
          "text": "Dinheiro disponível em conta"
        },
        {
          "feedback": "A dotação não obriga nem garante pagamento imediato. O pagamento depende de haver recursos financeiros efetivamente arrecadados e disponíveis no caixa.",
          "isCorrect": false,
          "text": "Garantia de pagamento imediato"
        },
        {
          "feedback": "A dotação apenas autoriza a despesa dentro do orçamento; ela não substitui os procedimentos de contratação nem cria dinheiro novo no caixa.",
          "isCorrect": false,
          "text": "Dispensa das etapas da despesa"
        }
      ],
      "question": "O que a dotação orçamentária realmente garante nesse caso?"
